// Mirrors React-template Clients.jsx — client-logo-style-01 to 06

export interface ClientItem {
  img: string;
  link?: string;
}

interface Props {
  theme?: "client-logo-style-01" | "client-logo-style-02" | "client-logo-style-03" | "client-logo-style-04" | "client-logo-style-05" | "client-logo-style-06" | "client-logo-style-07" | "client-logo-style-08";
  data: ClientItem[];
  grid?: string;
}

export default function Clients({ theme = "client-logo-style-01", data, grid = "grid-cols-3 sm:grid-cols-4 lg:grid-cols-6" }: Props) {
  if (theme === "client-logo-style-07") {
    return (
      <div className={`client-logo-style-07 grid ${grid} gap-8 items-center justify-items-center`}>
        {data.map((c, i) => (
          <a key={i} href={c.link || "#"} className="cl-logo">
            <img src={c.img} alt="" />
          </a>
        ))}
      </div>
    );
  }

  if (theme === "client-logo-style-08") {
    return (
      <div className="client-logo-style-08">
        {data.map((c, i) => (
          <a key={i} href={c.link || "#"} className="cl-logo">
            <img src={c.img} alt="" />
          </a>
        ))}
      </div>
    );
  }

  // style-06: list with divider between
  if (theme === "client-logo-style-06") {
    return (
      <div className="flex flex-wrap items-center justify-center gap-0 divide-x divide-[--border]">
        {data.map((c, i) => (
          <a key={i} href={c.link || "#"} className="client-logo px-8 py-4 flex items-center justify-center">
            <img src={c.img} alt="" />
          </a>
        ))}
      </div>
    );
  }

  // style-02 to 05: slight size / filter variations
  const opacity =
    theme === "client-logo-style-02" ? "opacity-60" :
    theme === "client-logo-style-03" ? "opacity-40" :
    theme === "client-logo-style-04" ? "opacity-70" :
    theme === "client-logo-style-05" ? "opacity-50" :
    "opacity-50";

  return (
    <div className={`grid ${grid} gap-8 items-center justify-items-center`}>
      {data.map((c, i) => (
        <a key={i} href={c.link || "#"} className={`client-logo ${opacity} hover:opacity-100 transition-opacity`}>
          <img src={c.img} alt="" />
        </a>
      ))}
    </div>
  );
}
