// Mirrors React-template Team.jsx — team-style-01 to 03

import { brandIcon } from "@/components/icons/brandIcons";
import type { ReactNode } from "react";

interface TeamSocialLink {
  icon: ReactNode;
  link: string;
  label?: string;
}

export interface TeamMember {
  name: string;
  designation: string;
  img: string;
  social?: TeamSocialLink[];
}

interface Props {
  theme?: "team-style-01" | "team-style-02" | "team-style-03" | "team-style-04" | "team-style-05";
  data: TeamMember[];
  grid?: string;
  overlay?: [string, string];
}

const DEFAULT_SOCIAL = [
  { icon: brandIcon("facebook"), link: "#", label: "Facebook" },
  { icon: brandIcon("linkedin"), link: "#", label: "LinkedIn" },
  { icon: brandIcon("twitter"), link: "#", label: "Twitter" },
];

export default function Team({ theme = "team-style-01", data, grid = "grid-cols-2 lg:grid-cols-4", overlay }: Props) {
  return (
    <div className={`grid ${grid} gap-6`}>
      {data.map((member, i) => {
        if (theme === "team-style-02") return <Style02 key={i} member={member} overlay={overlay} />;
        if (theme === "team-style-03") return <Style03 key={i} member={member} overlay={overlay} />;
        if (theme === "team-style-04") return <Style04 key={i} member={member} />;
        if (theme === "team-style-05") return <Style05 key={i} member={member} />;
        return <Style01 key={i} member={member} />;
      })}
    </div>
  );
}

function SocialLinks({ links }: { links?: TeamSocialLink[] }) {
  return (
    <div className="t-social">
      {(links || DEFAULT_SOCIAL).map((s, i) => (
        <a key={i} href={s.link} aria-label={s.label || "Social link"} target="_blank" rel="noopener noreferrer">{s.icon}</a>
      ))}
    </div>
  );
}

function Style01({ member }: { member: TeamMember }) {
  return (
    <div className="team-01">
      <div className="t-img">
        <img src={member.img} alt={member.name} />
      </div>
      <h5>{member.name}</h5>
      <div className="t-role">{member.designation}</div>
      <SocialLinks links={member.social} />
    </div>
  );
}

function Style02({ member, overlay }: { member: TeamMember; overlay?: [string, string] }) {
  const bg = overlay
    ? `linear-gradient(135deg, ${overlay[0]}, ${overlay[1]})`
    : "linear-gradient(135deg, rgba(0,85,212,0.9), rgba(26,35,50,0.88))";
  return (
    <div className="team-02">
      <img src={member.img} alt={member.name} />
      <div className="t-overlay" style={{ background: bg }}>
        <h5>{member.name}</h5>
        <div className="t-role">{member.designation}</div>
        <SocialLinks links={member.social} />
      </div>
    </div>
  );
}

function Style04({ member }: { member: TeamMember }) {
  return (
    <figure className="team-04">
      <img src={member.img} alt={member.name} />
      <div className="t-overlay">
        {member.social?.slice(0, 1).map((s, i) => (
          <div key={i} className="t-quote">{s.icon}</div>
        ))}
        <SocialLinks links={member.social} />
      </div>
      <figcaption>
        <div className="t-name">{member.name}</div>
        <div className="t-role">{member.designation}</div>
      </figcaption>
    </figure>
  );
}

function Style05({ member }: { member: TeamMember }) {
  return (
    <div className="team-05">
      <img src={member.img} alt={member.name} />
      <div className="t-caption">
        <div className="t-name">{member.name}</div>
        <div className="t-role">{member.designation}</div>
        <SocialLinks links={member.social} />
      </div>
    </div>
  );
}

function Style03({ member, overlay }: { member: TeamMember; overlay?: [string, string] }) {
  const bg = overlay
    ? `linear-gradient(135deg, ${overlay[0]}e6, ${overlay[1]})`
    : "linear-gradient(135deg, rgba(0,85,212,0.92), rgba(26,35,50,0.88))";
  return (
    <div className="team-03">
      <img src={member.img} alt={member.name} />
      <div className="t-overlay" style={{ background: bg }}>
        <div className="t-info">
          <h5>{member.name}</h5>
          <div className="t-role">{member.designation}</div>
          <SocialLinks links={member.social} />
        </div>
      </div>
    </div>
  );
}
