// Mirrors React-template GoogleMap.jsx — embedded iframe

interface Props {
  src?: string;
  height?: number;
}

const DEFAULT_SRC = "https://www.google.com/maps/embed?pb=!1m17!1m12!1m3!1d971.8!2d79.7966!3d11.9450!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m2!1m1!2s!5e0!3m2!1sen!2sin!4v1700000000000!5m2!1sen!2sin&center=11.944961,79.796656&zoom=17";

export default function GoogleMap({ src = DEFAULT_SRC, height = 450 }: Props) {
  return (
    <div className="gmap-wrap">
      <iframe
        src={src}
        height={height}
        loading="lazy"
        referrerPolicy="no-referrer-when-downgrade"
        title="Google Map"
        allowFullScreen
      />
    </div>
  );
}
